//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageec2_testimport("regexp""testing""github.com/YakDriver/regexache"tfec2"github.com/hashicorp/terraform-provider-aws/internal/service/ec2")arallel()testCases:=[]struct{TestNameInputARNExpectedError*regexp.RegexpExpectedNamestring}{{TestName:N",InputARN:ExpectedError:regexache.MustCompile(`parsingARN`),},{TestName:leARN",InputARN:ExpectedError:regexache.MustCompile(`parsingARN`),},{TestName:ARNservice",InputARN:ec2:us-east-1:123456789012:instance/i-12345678",//lintignore:AWSAT003,AWSAT005ExpectedError:regexache.MustCompile(`expectedserviceiam`),},{TestName:ARNresourceparts",InputARN:iam:us-east-1:123456789012:name",//lintignore:AWSAT003,AWSAT005ExpectedError:regexache.MustCompile(`expectedatleast2resourceparts`),},{TestName:ARNresourceprefix",InputARN:iam:us-east-1:123456789012:role/name",//lintignore:AWSAT003,AWSAT005ExpectedError:regexache.MustCompile(`expectedresourceprefixinstance-profile`),},{TestName:",InputARN:am:us-east-1:123456789012:instance-profile/name",//lintignore:AWSAT003,AWSAT005ExpectedName:"name",},{TestName:withmultipleparts",InputARN:am:us-east-1:123456789012:instance-profile/path/name",//lintignore:AWSAT003,AWSAT005ExpectedName:"name",},}for_,testCase:=rangetestCases{testCase:=testCaset.Run(testCase.TestName,(t*testing.T){got,err:=tfec2.InstanceProfileARNToName(testCase.InputARN)iferr==nil&&testCase.ExpectedError!=nil{t.Fatalf("expectederror%s,gotnoerror",testCase.ExpectedError.String())}iferr!=nil&&testCase.ExpectedError==nil{t.Fatalf("gotunexpectederror:%s",err)}iferr!=nil&&!testCase.ExpectedError.MatchString(err.Error()){t.Fatalf("expectederror%s,got:%s",testCase.ExpectedError.String(),err)}ifgot!=testCase.ExpectedName{t.Errorf("got%s,expected%s",got,testCase.ExpectedName)}})}}